+
+fn test_issue(id: &str, priority: u8) -> BeadIssueDetail {
+    BeadIssueDetail {
+        id: id.to_string(),
+        title: format!("Test bead {id}"),
+        status: BeadStatus::Open,
+        priority,
+        issue_type: BeadIssueType::Task,
+        assignee: None,
+        labels: Vec::new(),
+        dependencies: Vec::new(),
+        dependents: Vec::new(),
+        parent: None,
+        ingest_warning: None,
+        extra: HashMap::new(),
+    }
+}
+
