+        agent_id: agent_id.to_string(),
+        capabilities: vec!["robot.send".to_string()],
+        lane_affinity: Vec::new(),
+        current_load: 0,
+        max_parallel_assignments: 3,
+        availability: MissionAgentAvailability::Ready,
