+        "ttl-test",
+        OperatorOverrideKind::Exclude {
+            bead_id: "x".to_string(),
+        },
+    );
+    // expires_at_ms = 5000
+    assert!(!ovr.is_expired(4999));
+    assert!(ovr.is_expired(5000));
+    assert!(ovr.is_expired(5001));
+}
